import base64
import zlib
from .xml_validator import (
    parse_saml_xml,
    validate_saml_response_structure,
    find_assertion,
    SAML_NAMESPACES,
)
from .exceptions import SAMLParsingError, SAMLResponseError


class SAMLResponseParser:
    """
    Parses a SAML Response and extracts user information.
    """

    def __init__(self, saml_response_b64, attribute_mapping=None):
        self.raw_response = saml_response_b64
        self.attribute_mapping = attribute_mapping or {}
        self.xml_string = None
        self.root = None
        self.assertion = None
        self.name_id = None
        self.name_id_format = None
        self.session_index = None
        self.attributes = {}
        self.issuer = None

    def decode_response(self):
        """Decode the base64-encoded SAML Response."""
        try:
            self.xml_string = base64.b64decode(self.raw_response)
        except Exception as e:
            raise SAMLParsingError(f"Failed to base64 decode SAML Response: {e}")

        # Try to decompress if it's deflated
        try:
            self.xml_string = zlib.decompress(self.xml_string, -15)
        except zlib.error:
            pass  # Not compressed, use as-is

        if isinstance(self.xml_string, bytes):
            try:
                self.xml_string = self.xml_string.decode('utf-8')
            except UnicodeDecodeError:
                pass

        return self.xml_string

    def parse(self):
        """Parse and validate the SAML Response."""
        self.decode_response()
        self.root = parse_saml_xml(self.xml_string)
        validate_saml_response_structure(self.root)
        self.assertion = find_assertion(self.root)

        if self.assertion is None:
            raise SAMLResponseError("No assertion found in SAML Response")

        self._extract_issuer()
        self._extract_name_id()
        self._extract_session_index()
        self._extract_attributes()

        return self

    def _extract_issuer(self):
        """Extract the Issuer from the Response and/or Assertion."""
        for ns_prefix in ['saml', 'saml2']:
            ns = SAML_NAMESPACES.get(ns_prefix, '')
            # Try Response-level Issuer first
            issuer_elem = self.root.find(f'{{{ns}}}Issuer')
            if issuer_elem is not None and issuer_elem.text:
                self.issuer = issuer_elem.text.strip()
                return

        # Try Assertion-level Issuer
        if self.assertion is not None:
            for ns_prefix in ['saml', 'saml2']:
                ns = SAML_NAMESPACES.get(ns_prefix, '')
                issuer_elem = self.assertion.find(f'{{{ns}}}Issuer')
                if issuer_elem is not None and issuer_elem.text:
                    self.issuer = issuer_elem.text.strip()
                    return

    def _extract_name_id(self):
        """Extract the NameID from the Assertion Subject."""
        subject = None
        for ns_prefix in ['saml', 'saml2']:
            ns = SAML_NAMESPACES.get(ns_prefix, '')
            subject = self.assertion.find(f'{{{ns}}}Subject')
            if subject is not None:
                break

        if subject is None:
            raise SAMLResponseError("No Subject found in Assertion")

        name_id_elem = None
        for ns_prefix in ['saml', 'saml2']:
            ns = SAML_NAMESPACES.get(ns_prefix, '')
            name_id_elem = subject.find(f'{{{ns}}}NameID')
            if name_id_elem is not None:
                break

        if name_id_elem is None:
            raise SAMLResponseError("No NameID found in Subject")

        self.name_id = name_id_elem.text.strip() if name_id_elem.text else None
        self.name_id_format = name_id_elem.get('Format', '')

        if not self.name_id:
            raise SAMLResponseError("NameID is empty")

    def _extract_session_index(self):
        """Extract the SessionIndex from the AuthnStatement."""
        for ns_prefix in ['saml', 'saml2']:
            ns = SAML_NAMESPACES.get(ns_prefix, '')
            authn_statement = self.assertion.find(f'{{{ns}}}AuthnStatement')
            if authn_statement is not None:
                self.session_index = authn_statement.get('SessionIndex', '')
                return

    def _extract_attributes(self):
        """Extract attributes from the Assertion's AttributeStatement."""
        attr_statement = None
        for ns_prefix in ['saml', 'saml2']:
            ns = SAML_NAMESPACES.get(ns_prefix, '')
            attr_statement = self.assertion.find(f'{{{ns}}}AttributeStatement')
            if attr_statement is not None:
                break

        if attr_statement is None:
            return

        for ns_prefix in ['saml', 'saml2']:
            ns = SAML_NAMESPACES.get(ns_prefix, '')
            for attribute in attr_statement.findall(f'{{{ns}}}Attribute'):
                attr_name = attribute.get('Name', '')
                attr_friendly_name = attribute.get('FriendlyName', '')

                values = []
                for attr_value in attribute.findall(f'{{{ns}}}AttributeValue'):
                    if attr_value.text:
                        values.append(attr_value.text.strip())

                # Store by Name
                if attr_name:
                    self.attributes[attr_name] = values

                # Also store by FriendlyName if available
                if attr_friendly_name:
                    self.attributes[attr_friendly_name] = values

    def get_mapped_attributes(self):
        """
        Map SAML attributes to user-friendly names based on attribute_mapping.
        Returns a dict like {'email': 'user@example.com', 'first_name': 'John', ...}
        """
        mapped = {}

        for field_name, possible_attr_names in self.attribute_mapping.items():
            for attr_name in possible_attr_names:
                if attr_name in self.attributes:
                    values = self.attributes[attr_name]
                    if field_name == 'groups':
                        mapped[field_name] = values
                    elif values:
                        mapped[field_name] = values[0]
                    break

        return mapped

    def get_user_info(self):
        """
        Get complete user information extracted from the SAML Response.
        """
        mapped_attrs = self.get_mapped_attributes()

        return {
            'name_id': self.name_id,
            'name_id_format': self.name_id_format,
            'session_index': self.session_index,
            'issuer': self.issuer,
            'attributes': self.attributes,
            'mapped_attributes': mapped_attrs,
            'email': mapped_attrs.get('email', self.name_id),
            'first_name': mapped_attrs.get('first_name', ''),
            'last_name': mapped_attrs.get('last_name', ''),
            'groups': mapped_attrs.get('groups', []),
        }


# saml_sp/auth_backend.py
import logging
from django.conf import settings
from django.contrib.auth import get_user_model
from django.contrib.auth.backends import ModelBackend

logger = logging.getLogger(__name__)
User = get_user_model()


class SAMLAuthenticationBackend(ModelBackend):
    """
    Django authentication backend for SAML-based authentication.
    Creates or updates users based on SAML assertion data.
    """

    def authenticate(self, request, saml_user_info=None, **kwargs):
        """
        Authenticate a user based on SAML assertion data.
        """
        if saml_user_info is None:
            return None

        saml_settings = getattr(settings, 'SAML_SP_SETTINGS', {})
        create_unknown = saml_settings.get('create_unknown_user', True)
        update_on_login = saml_settings.get('update_user_on_login', True)

        name_id = saml_user_info.get('name_id')
        email = saml_user_info.get('email', name_id)
        first_name = saml_user_info.get('first_name', '')
        last_name = saml_user_info.get('last_name', '')

        if not name_id:
            logger.error("SAML authentication failed: No NameID provided")
            return None

        # Determine username - use email if it looks like an email, otherwise use name_id
        username = self._determine_username(name_id, email)

        user = None

        # Try to find existing user
        try:
            # First try by email
            if email and '@' in email:
                try:
                    user = User.objects.get(email=email)
                except User.DoesNotExist:
                    pass
                except User.MultipleObjectsReturned:
                    user = User.objects.filter(email=email).first()

            # Then try by username
            if user is None:
                try:
                    user = User.objects.get(username=username)
                except User.DoesNotExist:
                    pass

        except Exception as e:
            logger.error(f"Error looking up SAML user: {e}")
            return None

        if user is None:
            if not create_unknown:
                logger.warning(
                    f"SAML user '{username}' not found and create_unknown_user is False"
                )
                return None

            # Create new user
            try:
                user = self._create_user(username, email, first_name, last_name)
                logger.info(f"Created new SAML user: {username}")
            except Exception as e:
                logger.error(f"Failed to create SAML user '{username}': {e}")
                return None

        elif update_on_login:
            # Update existing user
            try:
                self._update_user(user, email, first_name, last_name)
                logger.info(f"Updated SAML user: {username}")
            except Exception as e:
                logger.error(f"Failed to update SAML user '{username}': {e}")

        # Handle group assignments
        groups = saml_user_info.get('groups', [])
        if groups:
            self._update_user_groups(user, groups)

        # Ensure user is active
        if not user.is_active:
            logger.warning(f"SAML user '{username}' is inactive")
            return None

        return user

    def _determine_username(self, name_id, email):
        """Determine the username from NameID and email."""
        # If name_id looks like an email, use the local part
        if '@' in name_id:
            username = name_id.split('@')[0]
        elif email and '@' in email:
            username = email.split('@')[0]
        else:
            username = name_id

        # Sanitize username
        username = username.strip().lower()
        # Replace characters that might not be allowed in usernames
        username = username.replace(' ', '_').replace('.', '_')

        # Ensure username is not too long (Django default max is 150)
        max_length = 150
        if hasattr(User, '_meta'):
            username_field = User._meta.get_field('username')
            if hasattr(username_field, 'max_length') and username_field.max_length:
                max_length = username_field.max_length

        return username[:max_length]

    def _create_user(self, username, email, first_name, last_name):
        """Create a new Django user from SAML data."""
        user = User(
            username=username,
            email=email or '',
            first_name=first_name or '',
            last_name=last_name or '',
            is_active=True,
        )
        # Set unusable password since auth is via SAML
        user.set_unusable_password()
        user.save()
        return user

    def _update_user(self, user, email, first_name, last_name):
        """Update an existing user with SAML data."""
        updated = False

        if email and user.email != email:
            user.email = email
            updated = True

        if first_name and user.first_name != first_name:
            user.first_name = first_name
            updated = True

        if last_name and user.last_name != last_name:
            user.last_name = last_name
            updated = True

        if updated:
            user.save()

    def _update_user_groups(self, user, group_names):
        """Update user group memberships based on SAML groups."""
        from django.contrib.auth.models import Group

        current_groups = set(user.groups.values_list('name', flat=True))
        saml_groups = set(group_names)

        # Add user to new groups
        groups_to_add = saml_groups - current_groups
        for group_name in groups_to_add:
            try:
                group, created = Group.objects.get_or_create(name=group_name)
                user.groups.add(group)
                if created:
                    logger.info(f"Created new group: {group_name}")
            except Exception as e:
                logger.error(f"Failed to add user to group '{group_name}': {e}")

        # Optionally remove user from groups not in SAML response
        # Uncomment the following if you want SAML to be the source of truth for groups:
        # groups_to_remove = current_groups - saml_groups
        # for group_name in groups_to_remove:
        #     try:
        #         group = Group.objects.get(name=group_name)
        #         user.groups.remove(group)
        #     except Group.DoesNotExist:
        #         pass


# saml_sp/session_manager.py
import logging
from django.conf import settings
from django.contrib.auth import login as django_login, authenticate

logger = logging.getLogger(__name__)


class SAMLSessionManager:
    """
    Manages Django user sessions based on SAML authentication.
    """

    @staticmethod
    def create_session(request, saml_user_info):
        """
        Create a Django session for the authenticated SAML user.

        Args:
            request: Django HttpRequest
            saml_user_info: Dict with user info from SAMLResponseParser.get_user_info()

        Returns:
            The authenticated User object, or None if authentication failed.
        """
        # Authenticate using our SAML backend
        user = authenticate(request, saml_user_info=saml_user_info)

        if user is None:
            logger.error("SAML authentication failed - no user returned from backend")
            return None

        # Log the user in and create the Django session
        django_login(request, user, backend='saml_sp.auth_backend.SAMLAuthenticationBackend')

        # Store SAML-specific data in the session
        request.session['saml_authenticated'] = True
        request.session['saml_name_id'] = saml_user_info.get('name_id', '')
        request.session['saml_name_id_format'] = saml_user_info.get('name_id_format', '')
        request.session['saml_session_index'] = saml_user_info.get('session_index', '')
        request.session['saml_issuer'] = saml_user_info.get('issuer', '')

        # Store mapped attributes for later use
        request.session['saml_attributes'] = saml_user_info.get('mapped_attributes', {})

        # Set session expiry
        saml_settings = getattr(settings, 'SAML_SP_SETTINGS', {})
        session_expiry = saml_settings.get('session_expiry', None)
        if session_expiry:
            request.session.set_expiry(session_expiry)

        logger.info(
            f"SAML session created for user '{user.username}' "
            f"(NameID: {saml_user_info.get('name_id')})"
        )

        return user

    @staticmethod
    def is_saml_authenticated(request):
        """Check if the current session was authenticated via SAML."""
        return request.session.get('saml_authenticated', False)

    @staticmethod
    def get_saml_session_info(request):
        """Get SAML session information from the current session."""
        if not request.session.get('saml_authenticated', False):
            return None

        return {
            'name_id': request.session.get('saml_name_id', ''),
            'name_id_format': request.session.get('saml_name_id_format', ''),
            'session_index': request.session.get('saml_session_index', ''),
            'issuer': request.session.get('saml_issuer', ''),
            'attributes': request.session.get('saml_attributes', {}),
        }


