import logging
from django.conf import settings
from django.http import HttpResponseBadRequest, HttpResponseRedirect, HttpResponse
from django.views import View
from django.views.decorators.csrf import csrf_exempt
from django.utils.decorators import method_decorator
from django.urls import reverse

from .parser import SAMLResponseParser
from .session_manager import SAMLSessionManager
from .exceptions import SAMLError

logger = logging.getLogger(__name__)


@method_decorator(csrf_exempt, name='dispatch')
class SAMLACSView(View):
    """
    Assertion Consumer Service (ACS) endpoint.
    Handles SAML POST responses from the Identity Provider.
    """

    def post(self, request):
        """Handle SAML Response POST."""
        saml_response_b64 = request.POST.get('SAMLResponse')
        relay_state = request.POST.get('RelayState', '')

        if not saml_response_b64:
            logger.error("No SAMLResponse found in POST data")
            return HttpResponseBadRequest("Missing SAMLResponse parameter")

        try:
            # Get SAML settings
            saml_settings = getattr(settings, 'SAML_SP_SETTINGS', {})
            attribute_mapping = saml_settings.get('attribute_mapping', {})

            # Parse the SAML Response
            parser = SAMLResponseParser(
                saml_response_b64,
                attribute_mapping=attribute_mapping,
            )
            parser.parse()

            # Extract user information
            user_info = parser.get_user_info()

            logger.info(
                f"SAML Response parsed successfully. "
                f"NameID: {user_info['name_id']}, "
                f"Issuer: {user_info['issuer']}"
            )

            # Create Django session
            user = SAMLSessionManager.create_session(request, user_info)

            if user is None:
                logger.error("Failed to create session for SAML user")
                return HttpResponseBadRequest(
                    "Authentication failed. Unable to create user session."
                )

            # Redirect to RelayState or default URL
            redirect_url = relay_state or saml_settings.get(
                'default_redirect_url', '/'
            )

            # Validate redirect URL to prevent open redirect
            if not self._is_safe_redirect(redirect_url):
                redirect_url = '/'

            return HttpResponseRedirect(redirect_url)

        except SAMLError as e:
            logger.error(f"SAML Error: {e}")
            return HttpResponseBadRequest(f"SAML Error: {e}")
        except Exception as e:
            logger.exception(f"Unexpected error processing SAML Response: {e}")
            return HttpResponseBadRequest("An error occurred processing the SAML response")

    def _is_safe_redirect(self, url):
        """Check if the redirect URL is safe (relative or same-host)."""
        if not url:
            return False
        # Only allow relative URLs
        if url.startswith('/') and not url.startswith('//'):
            return True
        # Check if it's the same host
        allowed_hosts = getattr(settings, 'ALLOWED_HOSTS', [])
        from urllib.parse import urlparse
        parsed = urlparse(url)
        if parsed.hostname and parsed.hostname in allowed_hosts:
            return True
        return False


class SAMLLoginView(View):
    """
    Initiates SAML authentication by redirecting to the IdP.
    """

    def get(self, request):
        """Redirect to IdP for authentication."""
        saml_settings = getattr(settings, 'SAML_SP_SETTINGS', {})
        idp_sso_url = saml_settings.get('idp_sso_url', '')

        if not idp_sso_url:
            return HttpResponseBadRequest("IdP SSO URL not configured")

        entity_id = saml_settings.get('entity_id', '')
        acs_url = saml_settings.get('acs_url', '')

        # Build a simple SAML AuthnRequest
        import uuid
        import datetime
        request_id = f"_{''.join(str(uuid.uuid4()).split('-'))}"
        issue_instant = datetime.datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')

        authn_request = f'''<samlp:AuthnRequest
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{idp_sso_url}"
    AssertionConsumerServiceURL="{acs_url}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{entity_id}</saml:Issuer>
    <samlp:NameIDPolicy
        Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
        AllowCreate="true"/>
</samlp:AuthnRequest>'''

        import base64
        encoded_request = base64.b64encode(authn_request.encode('utf-8')).decode('utf-8')

        # Store relay state (the page the user wanted to visit)
        relay_state = request.GET.get('next', '/')

        # For HTTP-POST binding, render a form that auto-submits
        html = f'''<!DOCTYPE html>
<html>
<head><title>Redirecting to Identity Provider...</title></head>
<body onload="document.forms[0].submit();">
    <noscript>
        <p>JavaScript is disabled. Click the button below to continue.</p>
    </noscript>
    <form method="POST" action="{idp_sso_url}">
        <input type="hidden" name="SAMLRequest" value="{encoded_request}"/>
        <input type="hidden" name="RelayState" value="{relay_state}"/>
        <noscript>
            <input type="submit" value="Continue"/>
        </noscript>
    </form>
</body>
</html>'''

        return HttpResponse(html, content_type='text/html')


class SAMLMetadataView(View):
    """
    Serves the SP metadata XML.
    """

    def get(self, request):
        """Return SP metadata."""
        saml_settings = getattr(settings, 'SAML_SP_SETTINGS', {})
        entity_id = saml_settings.get('entity_id', '')
        acs_url = saml_settings.get('acs_url', '')

        metadata = f'''<?xml version="1.0" encoding="UTF-8"?>
<md:EntityDescriptor
    xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
    entityID="{entity_id}">
    <md:SPSSODescriptor
        AuthnRequestsSigned="false"
        WantAssertionsSigned="true"
        protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
        <md:NameIDFormat>urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress</md:NameIDFormat>
        <md:AssertionConsumerService
            Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
            Location="{acs_url}"
            index="1"
            isDefault="true"/>
    </md:SPSSODescriptor>
</md:EntityDescriptor>'''

        return HttpResponse(metadata, content_type='application/xml')


class SAMLLogoutView(View):
    """
    Handles SAML logout.
    """

    def get(self, request):
        """Process logout."""
        from django.contrib.auth import logout as django_logout

        # Get SAML session info before logout
        saml_info = SAMLSessionManager.get_saml_session_info(request)

        # Perform Django logout
        django_logout(request)

        saml_settings = getattr(settings, 'SAML_SP_SETTINGS', {})
        logout_redirect = saml_settings.get('logout_redirect_url', '/')

        return HttpResponseRedirect(logout_redirect)


