# saml_sp/middleware.py
import logging
from django.conf import settings
from django.http import HttpResponseRedirect
from django.urls import reverse

logger = logging.getLogger(__name__)


class SAMLAuthenticationMiddleware:
    """
    Middleware that ensures users are authenticated via SAML.
    Redirects unauthenticated users to the SAML login endpoint.
    """

    def __init__(self, get_response):
        self.get_response = get_response
        saml_settings = getattr(settings, 'SAML_SP_SETTINGS', {})
        self.exempt_urls = saml_settings.get('exempt_urls', [])
        self.require_saml = saml_settings.get('require_saml_auth', False)

    def __call__(self, request):
        if self.require_saml and not self._is_exempt(request):
            if not request.user.is_authenticated:
                login_url = reverse('saml_sp:login')
                next_url = request.get_full_path()
                return HttpResponseRedirect(f'{login_url}?next={next_url}')

        response = self.get_response(request)
        return response

    def _is_exempt(self, request):
        """Check if the current URL is exempt from SAML authentication."""
        path = request.path_info

        # Always exempt SAML endpoints
        saml_paths = ['/saml/acs/', '/saml/login/', '/saml/metadata/', '/saml/logout/']
        for saml_path in saml_paths:
            if path.startswith(saml_path):
                return True

        # Check configured exempt URLs
        for exempt_url in self.exempt_urls:
            if path.startswith(exempt_url):
                return True

        return False


# saml_sp/decorators.py
from functools import wraps
from django.http import HttpResponseForbidden
from .session_manager import SAMLSessionManager


def saml_authenticated_required(view_func):
    """
    Decorator that checks if the user was authenticated via SAML.
    """
    @wraps(view_func)
    def wrapper(request, *args, **kwargs):
        if not SAMLSessionManager.is_saml_authenticated(request):
            return HttpResponseForbidden(
                "Access denied. SAML authentication required."
            )
        return view_func(request, *args, **kwargs)
    return wrapper


def saml_group_required(*required_groups):
    """
    Decorator that checks if the SAML-authenticated user belongs to
    one of the required groups.
    """
    def decorator(view_func):
        @wraps(view_func)
        def wrapper(request, *args, **kwargs):
            if not SAMLSessionManager.is_saml_authenticated(request):
                return HttpResponseForbidden(
                    "Access denied. SAML authentication required."
                )

            saml_info = SAMLSessionManager.get_saml_session_info(request)
            if saml_info is None:
                return HttpResponseForbidden("Access denied. No SAML session found.")

            user_groups = set(saml_info.get('attributes', {}).get('groups', []))
            if not user_groups.intersection(set(required_groups)):
                return HttpResponseForbidden(
                    "Access denied. Insufficient group membership."
                )

            return view_func(request, *args, **kwargs)
        return wrapper
    return decorator


