class SAMLResponseParserTests(TestCase):
    """Tests for SAML Response parsing."""

    def test_parse_response(self):
        b64_response = base64.b64encode(
            SAMPLE_SAML_RESPONSE.encode('utf-8')
        ).decode('utf-8')

        parser = SAMLResponseParser(
            b64_response,
            attribute_mapping=TEST_SAML_SETTINGS['attribute_mapping'],
        )
        parser.parse()

        self.assertEqual(parser.name_id, 'john.doe@example.com')
        self.assertEqual(parser.session_index, '_session_789')
        self.assertEqual(parser.issuer, 'https://idp.example.com/')

    def test_extract_attributes(self):
        b64_response = base64.b64encode(
            SAMPLE_SAML_RESPONSE.encode('utf-8')
        ).decode('utf-8')

        parser = SAMLResponseParser(
            b64_response,
            attribute_mapping=TEST_SAML_SETTINGS['attribute_mapping'],
        )
        parser.parse()

        user_info = parser.get_user_info()
        self.assertEqual(user_info['email'], 'john.doe@example.com')
        self.assertEqual(user_info['first_name'], 'John')
        self.assertEqual(user_info['last_name'], 'Doe')
        self.assertIn('Admins', user_info['groups'])
        self.assertIn('Users', user_info['groups'])

    def test_mapped_attributes(self):
        b64_response = base64.b64encode(
            SAMPLE_SAML_RESPONSE.encode('utf-8')
        ).decode('utf-8')

        parser = SAMLResponseParser(
            b64_response,
            attribute_mapping=TEST_SAML_SETTINGS['attribute_mapping'],
        )
        parser.parse()

        mapped = parser.get_mapped_attributes()
        self.assertEqual(mapped['email'], 'john.doe@example.com')
        self.assertEqual(mapped['first_name'], 'John')
        self.assertEqual(mapped['last_name'], 'Doe')
        self.assertEqual(mapped['groups'], ['Admins', 'Users'])

    def test_invalid_base64(self):
        parser = SAMLResponseParser('not-valid-base64!!!')
        with self.assertRaises(SAMLParsingError):
            parser.parse()


