class SAMLAuthBackendTests(TestCase):
    """Tests for SAML authentication backend."""

    def setUp(self):
        self.backend = SAMLAuthenticationBackend()
        self.factory = RequestFactory()

    def test_authenticate_new_user(self):
        request = self.factory.get('/')
        add_session_to_request(request)

        user_info = {
            'name_id': 'john.doe@example.com',
            'email': 'john.doe@example.com',
            'first_name': 'John',
            'last_name': 'Doe',
            'groups': [],
        }

        user = self.backend.authenticate(request, saml_user_info=user_info)
        self.assertIsNotNone(user)
        self.assertEqual(user.email, 'john.doe@example.com')
        self.assertEqual(user.first_name, 'John')
        self.assertEqual(user.last_name, 'Doe')
        self.assertTrue(user.has_usable_password() is False)

    def test_authenticate_existing_user(self):
        existing_user = User.objects.create_user(
            username='john_doe',
            email='john.doe@example.com',
            first_name='OldFirst',
            last_name='OldLast',
        )

        request = self.factory.get('/')
        add_session_to_request(request)

        user_info = {
            'name_id': 'john.doe@example.com',
            'email': 'john.doe@example.com',
            'first_name': 'John',
            'last_name': 'Doe',
            'groups': [],
        }

        user = self.backend.authenticate(request, saml_user_info=user_info)
        self.assertIsNotNone(user)
        self.assertEqual(user.pk, existing_user.pk)
        # Should be updated
        user.refresh_from_db()
        self.assertEqual(user.first_name, 'John')
        self.assertEqual(user.last_name, 'Doe')

    def test_authenticate_no_saml_info(self):
        request = self.factory.get('/')
        user = self.backend.authenticate(request)
        self.assertIsNone(user)

    def test_authenticate_with_groups(self):
        from django.contrib.auth.models import Group

        request = self.factory.get('/')
        add_session_to_request(request)

        user_info = {
            'name_id': 'jane.doe@example.com',
            'email': 'jane.doe@example.com',
            'first_name': 'Jane',
            'last_name': 'Doe',
            'groups': ['Admins', 'Users'],
        }

        user = self.backend.authenticate(request, saml_user_info=user_info)
        self.assertIsNotNone(user)

        user_groups = list(user.groups.values_list('name', flat=True))
        self.assertIn('Admins', user_groups)
        self.assertIn('Users', user_groups)


