class SAMLSessionManagerTests(TestCase):
    """Tests for SAML session management."""

    def setUp(self):
        self.factory = RequestFactory()

    def test_create_session(self):
        request = self.factory.get('/')
        add_session_to_request(request)

        user_info = {
            'name_id': 'test.user@example.com',
            'name_id_format': 'urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress',
            'session_index': '_session_123',
            'issuer': 'https://idp.example.com/',
            'attributes': {},
            'mapped_attributes': {'email': 'test.user@example.com'},
            'email': 'test.user@example.com',
            'first_name': 'Test',
            'last_name': 'User',
            'groups': [],
        }

        user = SAMLSessionManager.create_session(request, user_info)
        self.assertIsNotNone(user)
        self.assertTrue(request.session.get('saml_authenticated'))
        self.assertEqual(
            request.session.get('saml_name_id'), 'test.user@example.com'
        )
        self.assertEqual(
            request.session.get('saml_session_index'), '_session_123'
        )

    def test_is_saml_authenticated(self):
        request = self.factory.get('/')
        add_session_to_request(request)

        self.assertFalse(SAMLSessionManager.is_saml_authenticated(request))

        request.session['saml_authenticated'] = True
        self.assertTrue(SAMLSessionManager.is_saml_authenticated(request))

    def test_get_saml_session_info(self):
        request = self.factory.get('/')
        add_session_to_request(request)

        # No SAML session
        self.assertIsNone(SAMLSessionManager.get_saml_session_info(request))

        # With SAML session
        request.session['saml_authenticated'] = True
        request.session['saml_name_id'] = 'user@example.com'
        request.session['saml_session_index'] = '_idx'
        request.session['saml_issuer'] = 'https://idp.example.com/'

        info = SAMLSessionManager.get_saml_session_info(request)
        self.assertIsNotNone(info)
        self.assertEqual(info['name_id'], 'user@example.com')
        self.assertEqual(info['session_index'], '_idx')


