class SAMLViewTests(TestCase):
    """Tests for SAML views."""

    def test_acs_post_valid(self):
        b64_response = base64.b64encode(
            SAMPLE_SAML_RESPONSE.encode('utf-8')
        ).decode('utf-8')

        response = self.client.post(
            '/saml/acs/',
            {'SAMLResponse': b64_response, 'RelayState': '/dashboard/'},
        )

        self.assertEqual(response.status_code, 302)
        self.assertEqual(response.url, '/dashboard/')

    def test_acs_post_missing_response(self):
        response = self.client.post('/saml/acs/', {})
        self.assertEqual(response.status_code, 400)

    def test_acs_get_not_allowed(self):
        response = self.client.get('/saml/acs/')
        self.assertEqual(response.status_code, 405)

    def test_metadata_view(self):
        response = self.client.get('/saml/metadata/')
        self.assertEqual(response.status_code, 200)
        self.assertEqual(response['Content-Type'], 'application/xml')
        self.assertIn(b'EntityDescriptor', response.content)

    def test_login_view(self):
        response = self.client.get('/saml/login/')
        self.assertEqual(response.status_code, 200)
        self.assertIn(b'SAMLRequest', response.content)

    def test_logout_view(self):
        response = self.client.get('/saml/logout/')
        self.assertEqual(response.status_code, 302)


